    'GB' => ['footer_note' => "<h2> ការផ្លាស់ប្តូរ E-commerce សម្រាប់ពាណិជ្ជកររបស់ប្រទេសអង់គ្លេសជាមួយនឹង Selldone Business OS</h2>\n\n<p> នៅក្នុងបេះដូងនៃទីផ្សារដ៏មមាញឹករបស់ប្រទេសអង់គ្លេស យុគសម័យថ្មីនៃពាណិជ្ជកម្មអេឡិចត្រូនិកកំពុងលេចឡើង។ Selldone Business OS ដែលជាវេទិកាពាណិជ្ជកម្មអេឡិចត្រូនិកគ្មានកម្មវិធីជំនួយ កំពុងរៀបចំឆាកសម្រាប់ពាណិជ្ជករទូទាំងប្រទេស។ ពីផលិតផលមួយទៅសេវាកម្ម ការជាវឯកសារ អ្វីៗទាំងអស់គឺស្ថិតនៅក្នុងការឈានទៅដល់។</p>\n\n<h3>Own Digital Space</h3> របស់អ្នក។\n<p>Merchants នៅក្នុងប្រទេសអង់គ្លេសឥឡូវនេះអាចបង្ហាញការផ្តល់ជូនរបស់ពួកគេដោយមោទនភាពនៅលើដែនផ្ទាល់ខ្លួនរបស់ពួកគេ។ មិនមានការសម្របសម្រួលទៀតទេ គ្រាន់តែជាអត្តសញ្ញាណម៉ាកសុទ្ធ និងទំនុកចិត្ត។</p>\n\n<h3> បទពិសោធន៍ការដំឡើងគ្មានថ្នេរ</h3>\n<p> បំភ្លេចពាក្យចចាមអារ៉ាមបច្ចេកទេស និងបញ្ជីគ្មានទីបញ្ចប់នៃតម្រូវការជាមុន។ ការដំឡើងជាមួយ Selldone គឺជាខ្យល់។ មិនចាំបាច់ស្វែងយល់ពីភាពស្មុគស្មាញនៃការបង្ហោះ ឬចំណាយបន្ថែមលើកម្មវិធីជំនួយ និងគំរូទេ។ វាទាំងអស់អំពីភាពសាមញ្ញ និងប្រសិទ្ធភាព។</p>\n\n<h3>England- ការគណនាពន្ធរួចរាល់</h3>\n<p> ជាមួយនឹងការយល់ដឹងយ៉ាងស៊ីជម្រៅអំពីប្រព័ន្ធពន្ធរបស់ប្រទេសអង់គ្លេស Selldone ផ្តល់នូវលក្ខណៈពិសេសនៃការគណនាពន្ធដែលរួមបញ្ចូលគ្នាយ៉ាងពេញលេញ។ ការ​អនុលោម​តាម​ច្បាប់​មិន​មែន​ជា​ផ្លូវ​ត្រង់​ទៀត​ទេ​។​</p>\n\n<h3> សម្រាប់ម៉ាកដែលកំពុងកើនឡើង</h3>\n<p> មិនថាអ្នកជាអ្នកចាប់ផ្តើមអាជីវកម្មថ្មី ឬយីហោដែលបានបង្កើតឡើងនៅក្នុងប្រទេសអង់គ្លេសទេ Selldone ធ្វើមាត្រដ្ឋានជាមួយអ្នក។ វាត្រូវបានបង្កើតឡើងសម្រាប់ការរីកចម្រើន ដែលធានាថាអ្នកតែងតែឈានមួយជំហានទៅមុខ។</p>\n\n<h3> ល្អបំផុតសម្រាប់ការបំប្លែងអតិបរមា</h3>\n<p> ធាតុទាំងអស់នៃ Selldone ត្រូវបានបង្កើតឡើងដើម្បីបង្វែរភ្ញៀវឱ្យទៅជាអតិថិជន។ វាមិនមែនគ្រាន់តែអំពីការលក់ទេ។ វានិយាយអំពីការលក់ smart.</p>\n\n<h3> ការលើកទឹកចិត្តដែលចូលរួម</h3>\n<ul>\n    <li><b> លេខកូដបញ្ចុះតម្លៃ</b> ដើម្បីផ្តល់រង្វាន់ដល់អ្នកឧបត្ថម្ភដ៏ស្មោះត្រង់។</li>\n    <li><b> ការផ្តល់ជូនពិសេស</b> ដើម្បីទាក់ទាញទស្សនិកជនថ្មី។</li>\n    <li><b>Cross-Sells and Upsells</b> ដើម្បីបង្កើនតម្លៃប្រតិបត្តិការ។</li>\n    <li><b>Gift លក្ខណៈពិសេស</b> សម្រាប់ឱកាសពិសេសទាំងនោះ។</li>\n</ul>\n\n<h3> ទីផ្សារស្វ័យប្រវត្តិ Magic</h3>\n<p> ជាមួយនឹងឧបករណ៍ធ្វើទ